// apiService.js

const BASE_URL = 'https://api.example.com';

// Token storage (in-memory; in production, use AsyncStorage or SecureStore)
let authToken = null;
let refreshToken = null;

// ─── Token Management ────────────────────────────────────────────────

export const setTokens = (access, refresh) => {
  authToken = access;
  refreshToken = refresh;
};

export const getAuthToken = () => authToken;

export const clearTokens = () => {
  authToken = null;
  refreshToken = null;
};

// ─── Persistent Token Storage (AsyncStorage wrapper) ─────────────────

import AsyncStorage from '@react-native-async-storage/async-storage';

const TOKEN_KEY = '@auth_token';
const REFRESH_TOKEN_KEY = '@refresh_token';

export const persistTokens = async (access, refresh) => {
  try {
    await AsyncStorage.multiSet([
      [TOKEN_KEY, access],
      [REFRESH_TOKEN_KEY, refresh],
    ]);
    setTokens(access, refresh);
  } catch (error) {
    console.error('Failed to persist tokens:', error);
  }
};

export const loadPersistedTokens = async () => {
  try {
    const values = await AsyncStorage.multiGet([TOKEN_KEY, REFRESH_TOKEN_KEY]);
    const access = values[0][1];
    const refresh = values[1][1];
    if (access && refresh) {
      setTokens(access, refresh);
      return true;
    }
    return false;
  } catch (error) {
    console.error('Failed to load persisted tokens:', error);
    return false;
  }
};

export const clearPersistedTokens = async () => {
  try {
    await AsyncStorage.multiRemove([TOKEN_KEY, REFRESH_TOKEN_KEY]);
    clearTokens();
  } catch (error) {
    console.error('Failed to clear persisted tokens:', error);
  }
};

// ─── Custom API Error ────────────────────────────────────────────────

class ApiError extends Error {
  constructor(message, status, data) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
    this.data = data;
  }
}

// ─── Core Request Function ───────────────────────────────────────────

const DEFAULT_TIMEOUT = 15000; // 15 seconds

const request = async (endpoint, options = {}, retryOnUnauth = true) => {
  const {
    method = 'GET',
    body = null,
    headers = {},
    timeout = DEFAULT_TIMEOUT,
    isFormData = false,
  } = options;

  const url = `${BASE_URL}${endpoint}`;

  // Build headers
  const requestHeaders = {
    Accept: 'application/json',
    ...headers,
  };

  if (!isFormData) {
    requestHeaders['Content-Type'] = 'application/json';
  }

  if (authToken) {
    requestHeaders['Authorization'] = `Bearer ${authToken}`;
  }

  // Build fetch config
  const fetchConfig = {
    method,
    headers: requestHeaders,
  };

  if (body) {
    fetchConfig.body = isFormData ? body : JSON.stringify(body);
  }

  // Create abort controller for timeout
  const controller = new AbortController();
  fetchConfig.signal = controller.signal;

  const timeoutId = setTimeout(() => controller.abort(), timeout);

  try {
    const response = await fetch(url, fetchConfig);
    clearTimeout(timeoutId);

    // Handle 204 No Content
    if (response.status === 204) {
      return { success: true, data: null, status: 204 };
    }

    let responseData;
    const contentType = response.headers.get('content-type');
    if (contentType && contentType.includes('application/json')) {
      responseData = await response.json();
    } else {
      responseData = await response.text();
    }

    // Handle 401 - attempt token refresh
    if (response.status === 401 && retryOnUnauth && refreshToken) {
      const refreshed = await attemptTokenRefresh();
      if (refreshed) {
        return request(endpoint, options, false); // retry once
      } else {
        await clearPersistedTokens();
        throw new ApiError('Session expired. Please log in again.', 401, responseData);
      }
    }

    if (!response.ok) {
      const errorMessage =
        responseData?.message || responseData?.error || `Request failed with status ${response.status}`;
      throw new ApiError(errorMessage, response.status, responseData);
    }

    return {
      success: true,
      data: responseData,
      status: response.status,
    };
  } catch (error) {
    clearTimeout(timeoutId);

    if (error.name === 'AbortError') {
      throw new ApiError('Request timed out. Please check your connection.', 0, null);
    }

    if (error instanceof ApiError) {
      throw error;
    }

    // Network error (no internet, DNS failure, etc.)
    throw new ApiError(
      'Network error. Please check your internet connection.',
      0,
      null
    );
  }
};

// ─── Token Refresh ───────────────────────────────────────────────────

let isRefreshing = false;
let refreshSubscribers = [];

const onTokenRefreshed = (newToken) => {
  refreshSubscribers.forEach((callback) => callback(newToken));
  refreshSubscribers = [];
};

const addRefreshSubscriber = (callback) => {
  refreshSubscribers.push(callback);
};

const attemptTokenRefresh = async () => {
  if (isRefreshing) {
    // Wait for the ongoing refresh
    return new Promise((resolve) => {
      addRefreshSubscriber((newToken) => {
        resolve(!!newToken);
      });
    });
  }

  isRefreshing = true;

  try {
    const response = await fetch(`${BASE_URL}/auth/refresh`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
      body: JSON.stringify({ refreshToken }),
    });

    if (!response.ok) {
      isRefreshing = false;
      onTokenRefreshed(null);
      return false;
    }

    const data = await response.json();
    await persistTokens(data.accessToken, data.refreshToken || refreshToken);

    isRefreshing = false;
    onTokenRefreshed(data.accessToken);
    return true;
  } catch (error) {
    isRefreshing = false;
    onTokenRefreshed(null);
    return false;
  }
};

// ─── Authentication API ──────────────────────────────────────────────

export const authApi = {
  /**
   * Register a new user
   */
  register: async (email, password, name) => {
    const result = await request('/auth/register', {
      method: 'POST',
      body: { email, password, name },
    });

    if (result.data?.accessToken) {
      await persistTokens(result.data.accessToken, result.data.refreshToken);
    }

    return result;
  },

  /**
   * Log in with email and password
   */
  login: async (email, password) => {
    const result = await request('/auth/login', {
      method: 'POST',
      body: { email, password },
    });

    if (result.data?.accessToken) {
      await persistTokens(result.data.accessToken, result.data.refreshToken);
    }

    return result;
  },

  /**
   * Log out the current user
   */
  logout: async () => {
    try {
      await request('/auth/logout', { method: 'POST' });
    } catch (error) {
      // Even if the server call fails, clear local tokens
      console.warn('Logout API call failed:', error.message);
    } finally {
      await clearPersistedTokens();
    }
    return { success: true };
  },

  /**
   * Request a password reset email
   */
  forgotPassword: async (email) => {
    return request('/auth/forgot-password', {
      method: 'POST',
      body: { email },
    });
  },

  /**
   * Reset password with token
   */
  resetPassword: async (token, newPassword) => {
    return request('/auth/reset-password', {
      method: 'POST',
      body: { token, newPassword },
    });
  },

  /**
   * Change password (authenticated)
   */
  changePassword: async (currentPassword, newPassword) => {
    return request('/auth/change-password', {
      method: 'POST',
      body: { currentPassword, newPassword },
    });
  },
};

// ─── User Profile API ────────────────────────────────────────────────

export const userApi = {
  /**
   * Get the current user's profile
   */
  getProfile: async () => {
    return request('/user/profile');
  },

  /**
   * Update the current user's profile
   */
  updateProfile: async (profileData) => {
    return request('/user/profile', {
      method: 'PUT',
      body: profileData,
    });
  },

  /**
   * Partially update the current user's profile
   */
  patchProfile: async (partialData) => {
    return request('/user/profile', {
      method: 'PATCH',
      body: partialData,
    });
  },

  /**
   * Upload a profile avatar image
   */
  uploadAvatar: async (imageUri) => {
    const formData = new FormData();
    const filename = imageUri.split('/').pop();
    const match = /\.(\w+)$/.exec(filename);
    const type = match ? `image/${match[1]}` : 'image/jpeg';

    formData.append('avatar', {
      uri: imageUri,
      name: filename,
      type,
    });

    return request('/user/avatar', {
      method: 'POST',
      body: formData,
      isFormData: true,
    });
  },

  /**
   * Delete the current user's account
   */
  deleteAccount: async (password) => {
    return request('/user/account', {
      method: 'DELETE',
      body: { password },
    });
  },

  /**
   * Get another user's public profile
   */
  getUserById: async (userId) => {
    return request(`/users/${userId}`);
  },
};

// ─── Generic Data API (CRUD) ─────────────────────────────────────────

export const dataApi = {
  /**
   * Get a list of resources
   */
  getList: async (resource, params = {}) => {
    const queryString = buildQueryString(params);
    return request(`/${resource}${queryString}`);
  },

  /**
   * Get a single resource by ID
   */
  getById: async (resource, id) => {
    return request(`/${resource}/${id}`);
  },

  /**
   * Create a new resource
   */
  create: async (resource, data) => {
    return request(`/${resource}`, {
      method: 'POST',
      body: data,
    });
  },

  /**
   * Update a resource (full replacement)
   */
  update: async (resource, id, data) => {
    return request(`/${resource}/${id}`, {
      method: 'PUT',
      body: data,
    });
  },

  /**
   * Partially update a resource
   */
  patch: async (resource, id, data) => {
    return request(`/${resource}/${id}`, {
      method: 'PATCH',
      body: data,
    });
  },

  /**
   * Delete a resource
   */
  remove: async (resource, id) => {
    return request(`/${resource}/${id}`, {
      method: 'DELETE',
    });
  },
};

// ─── Utility: Build Query String ─────────────────────────────────────

const buildQueryString = (params) => {
  const entries = Object.entries(params).filter(
    ([, value]) => value !== undefined && value !== null && value !== ''
  );

  if (entries.length === 0) return '';

  const queryParts = entries.map(([key, value]) => {
    if (Array.isArray(value)) {
      return value
        .map((v) => `${encodeURIComponent(key)}=${encodeURIComponent(v)}`)
        .join('&');
    }
    return `${encodeURIComponent(key)}=${encodeURIComponent(value)}`;
  });

  return `?${queryParts.join('&')}`;
};

// ─── Export the raw request for custom endpoints ─────────────────────

export { request, ApiError };

// ─── Default Export ──────────────────────────────────────────────────

export default {
  auth: authApi,
  user: userApi,
  data: dataApi,
  request,
  setTokens,
  clearTokens,
  loadPersistedTokens,
  persistTokens,
  clearPersistedTokens,
};


